import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface UsageBreakdown {
  app: string;
  percentage: number;
}

interface BatteryData {
  device: string;
  battery: {
    chargeLevel: number;
    estimatedTimeRemaining: string;
  };
  usageBreakdown: UsageBreakdown[];
}

export default function Widget() {
  const batteryData = response.data as BatteryData;
  const { battery, usageBreakdown } = batteryData;
  const meta = response.meta;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: meta.theme === 'dark' ? '#303030' : '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              {batteryData.device} Battery Status
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: meta.primaryColor }}>
              {battery.chargeLevel}%
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Estimated time remaining: {battery.estimatedTimeRemaining}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 120 }}>
            <PieChart
              height={120}
              series={[
                {
                  data: usageBreakdown.map((usage) => ({
                    id: usage.app,
                    value: usage.percentage,
                    label: usage.app,
                  })),
                  colorScheme: [meta.primaryColor, meta.accentColor, '#FFC107', '#03A9F4'],
                },
              ]}
              sx={{
                '& .MuiPieSlice-root': {
                  stroke: '#FFFFFF',
                  strokeWidth: 1,
                },
              }}
            />
          </Box>

          <Stack direction="row" spacing={0.5}>
            {usageBreakdown.map((usage, index) => (
              <Chip
                key={index}
                label={`${usage.app}: ${usage.percentage}%`}
                sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: meta.primaryColor, color: '#FFFFFF' }}
              />
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
